struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id using operator<<
        stream << packet_id;

        // Write username using prefixed adaptor
        stream << hexi::prefixed(username);

        // Write scores count (as uint32_t in little endian) and then the elements
        // Using operator<< which internally calls write_container
        stream << hexi::prefixed(scores);

        // Write metadata using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor from the vector
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream from the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Call the serialise method of the packet on the stream
    packet.serialise(stream);

    // Return the vector containing the serialized data
    return buffer;
}
```

