#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create block_allocator instance
    hexi::block_allocator<int, element_count> allocator;

    // Demonstrate free list management through allocation/deallocation cycles

    // Initial state: free list has element_count blocks
    int* blocks[element_count];

    // Allocate all blocks (uses pop() internally)
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate(i);
        // Each allocation calls pop(), moving head pointer forward
    }

    // At this point, free list is empty (tail points to itself)

    // Deallocate one block (uses push() internally)
    allocator.deallocate(blocks[0]);
    // This calls push(), adding the block to the head of the free list

    // Allocate again to show the free list is reused
    int* new_block = allocator.allocate(99);
    // This calls pop(), reusing the previously deallocated block

    // Deallocate all remaining blocks to clean up
    for (size_t i = 1; i < element_count; ++i) {
        allocator.deallocate(blocks[i]);
    }

    // Final deallocate of the new block
    allocator.deallocate(new_block);

    // The allocator properly manages the free list through push/pop operations
}
