    std::vector<std::byte> buffer(1000);
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);

    hexi::pmc::buffer& buf_ref = adaptor;
    hexi::pmc::binary_stream_writer writer(static_cast<hexi::pmc::buffer_write&>(buf_ref));
    encode_varint(writer, original_value);

    hexi::pmc::binary_stream_reader reader(static_cast<hexi::pmc::buffer_read&>(buf_ref));
    T decoded_value = decode_varint<T>(reader);

    return decoded_value == original_value;
}

