        // Convert and write pressure
        auto converted_pressure = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization
        adaptor.read(sensor_id);

        // Read and convert temperatures
        temperatures.resize(adaptor.size() / sizeof(float)); // Assuming all remaining data is temperatures and pressure
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        double raw_pressure;
        adaptor.read(raw_pressure);
        hexi::endian::little_to_native_inplace(raw_pressure);
        pressure = raw_pressure;
    }
};

